function onLoad() {
	//Type appropriate comment here, and begin script below

	//RJ -ET - Story 1

	// STRY0074595 - OU External Flag
	g_form.showFieldMsg("u_external_flag", 
						"Check this field to create an External Organizational Unit. Uncheck this field to create an Internal Organizational Unit.", 
						"info");
	// STRY0074671 - hide members
	if(g_form.getValue('u_external_flag') == 'true'){
		g_form.hideRelatedList('x_153465_discovert_discover_office_members');
	}
}
